import sys

def is_tak_code(grid, i, j):
    # Check top-left 3x3 is all black
    for x in range(3):
        for y in range(3):
            if grid[i + x][j + y] != '#':
                return False

    # Check bottom-right 3x3 is all black
    for x in range(3):
        for y in range(3):
            if grid[i + 6 + x][j + 6 + y] != '#':
                return False

    # Check adjacent cells to top-left 3x3 are white
    for x in range(-1, 4):
        for y in range(-1, 4):
            if (x == 0 and y == 0) or (x == 1 and y == 0) or (x == 2 and y == 0) or \
               (x == 0 and y == 1) or (x == 1 and y == 1) or (x == 2 and y == 1) or \
               (x == 0 and y == 2) or (x == 1 and y == 2) or (x == 2 and y == 2):
                continue
            if 0 <= i + x < 9 and 0 <= j + y < 9:
                if grid[i + x][j + y] != '.':
                    return False

    # Check adjacent cells to bottom-right 3x3 are white
    for x in range(-1, 4):
        for y in range(-1, 4):
            if (x == 0 and y == 0) or (x == 1 and y == 0) or (x == 2 and y == 0) or \
               (x == 0 and y == 1) or (x == 1 and y == 1) or (x == 2 and y == 1) or \
               (x == 0 and y == 2) or (x == 1 and y == 2) or (x == 2 and y == 2):
                continue
            if 0 <= i + x < 9 and 0 <= j + y < 9:
                if grid[i + x][j + y] != '.':
                    return False

    return True

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    M = int(input[1])
    grid = input[2:N+2]

    result = []
    for i in range(N - 8):
        for j in range(M - 8):
            if is_tak_code(grid, i, j):
                result.append((i + 1, j + 1))

    for i, j in result:
        print(f"{i} {j}")

if __name__ == "__main__":
    main()
